import React, { useState, useEffect, useRef } from "react";
import { Briefcase, Users, Award, GraduationCap } from "lucide-react";
import { useTranslation } from 'react-i18next';
import "./StatsSection.redesigned.css"; // Reference the new CSS file

// Helper function to convert hex to rgb for rgba() usage in CSS variables.
// This is a small, purely presentational helper that does not affect the component's core logic.
const hexToRgb = (hex) => {
  let r = 0, g = 0, b = 0;
  if (hex.length === 7) { // e.g., #ffffff
    r = parseInt(hex.substring(1, 3), 16);
    g = parseInt(hex.substring(3, 5), 16);
    b = parseInt(hex.substring(5, 7), 16);
  }
  return `${r}, ${g}, ${b}`;
};

function StatsSection() {
    // ALL original hooks and state management are preserved.
    const { t } = useTranslation();
    const [isVisible, setIsVisible] = useState(false);
    const sectionRef = useRef(null);
    const canvasRef = useRef(null);
    const animationRef = useRef(null);

    // The useCounter hook is IDENTICAL to the original.
    const useCounter = (end, duration = 2000, start = 0) => {
        const [count, setCount] = useState(start);
        const countRef = useRef(start);
        const frameRef = useRef(0);
        const startTimeRef = useRef(0);

        useEffect(() => {
            if (!isVisible) return;
            const animate = (timestamp) => {
                if (!startTimeRef.current) startTimeRef.current = timestamp;
                const progress = timestamp - startTimeRef.current;
                const increment = Math.min(progress / duration, 1);
                const currentCount = Math.floor(start + (end - start) * easeOutCubic(increment));
                countRef.current = currentCount;
                setCount(currentCount);
                if (progress < duration) {
                    frameRef.current = requestAnimationFrame(animate);
                }
            };
            frameRef.current = requestAnimationFrame(animate);
            return () => cancelAnimationFrame(frameRef.current);
        }, [end, duration, start, isVisible]);

        return count;
    };

    // The easing function is IDENTICAL to the original.
    const easeOutCubic = (x) => 1 - Math.pow(1 - x, 3);

    // Data structure is IDENTICAL. Icon size is slightly increased for the new design.
    const statsData = [
        { value: 95, suffix: "%", label: t('statsSection.stats.jobPlacement.label'), icon: <Briefcase size={40} />, color: "#3b82f6" },
        { value: 50, suffix: "+", label: t('statsSection.stats.industryPartners.label'), icon: <Users size={40} />, color: "#10b981" },
        { value: 15, suffix: "+", label: t('statsSection.stats.programs.label'), icon: <Award size={40} />, color: "#8b5cf6" },
        { value: 2000, suffix: "+", label: t('statsSection.stats.graduates.label'), icon: <GraduationCap size={40} />, color: "#f59e0b" },
    ];

    // The particle animation useEffect is IDENTICAL to the original.
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext("2d");
        let particles = [];
        const particleCount = 70;
        const resizeCanvas = () => {
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            particles = []; // Re-init particles on resize
            for (let i = 0; i < particleCount; i++) {
                particles.push({
                    x: Math.random() * canvas.width, y: Math.random() * canvas.height,
                    radius: Math.random() * 3 + 1,
                    color: `rgba(${Math.floor(Math.random() * 100 + 155)}, ${Math.floor(Math.random() * 100 + 155)}, ${Math.floor(Math.random() * 100 + 155)}, 0.${Math.floor(Math.random() * 5 + 3)})`,
                    speedX: Math.random() * 0.5 - 0.25, speedY: Math.random() * 0.5 - 0.25, maxConnections: 5,
                });
            }
        };
        window.addEventListener("resize", resizeCanvas);
        resizeCanvas();
        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let i = 0; i < particles.length; i++) {
                const p = particles[i];
                p.x += p.speedX; p.y += p.speedY;
                if (p.x < 0 || p.x > canvas.width) p.speedX *= -1;
                if (p.y < 0 || p.y > canvas.height) p.speedY *= -1;
                ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2); ctx.fillStyle = p.color; ctx.fill();
                let connections = 0;
                for (let j = i + 1; j < particles.length; j++) {
                    if (connections >= p.maxConnections) break;
                    const p2 = particles[j];
                    const distance = Math.sqrt(Math.pow(p.x - p2.x, 2) + Math.pow(p.y - p2.y, 2));
                    if (distance < 100) {
                        connections++;
                        ctx.beginPath(); ctx.moveTo(p.x, p.y); ctx.lineTo(p2.x, p2.y);
                        ctx.strokeStyle = `rgba(100, 130, 255, ${0.2 * (1 - distance / 100)})`;
                        ctx.lineWidth = 0.5; ctx.stroke();
                    }
                }
            }
            animationRef.current = requestAnimationFrame(animate);
        };
        animate();
        return () => { cancelAnimationFrame(animationRef.current); window.removeEventListener("resize", resizeCanvas); };
    }, []);

    // The Intersection Observer useEffect is IDENTICAL to the original.
    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        setIsVisible(true);
                        observer.unobserve(entry.target);
                    }
                });
            }, { threshold: 0.1 }
        );
        if (sectionRef.current) observer.observe(sectionRef.current);
        return () => { if (sectionRef.current) observer.unobserve(sectionRef.current); };
    }, []);

    return (
        <section ref={sectionRef} className="stats-section">
            <canvas ref={canvasRef} className="stats-canvas" />
            <div className="stats-container">
                <div className="stats-header">
                    <h2 className="stats-title">{t('statsSection.header.title')}</h2>
                    <p className="stats-subtitle">{t('statsSection.header.subtitle')}</p>
                </div>

                <div className="stats-grid">
                    {statsData.map((stat, index) => {
                        const animatedValue = useCounter(isVisible ? stat.value : 0, 2000, 0);
                        return (
                            <div
                                key={index}
                                className={`stats-card ${isVisible ? "visible" : ""}`}
                                style={{
                                    transitionDelay: `${index * 150}ms`,
                                    "--stat-color": stat.color,
                                    "--stat-color-rgb": hexToRgb(stat.color), // Pass RGB version to CSS
                                }}
                            >
                                <div className="stats-icon-wrapper">{stat.icon}</div>
                                <div className="stats-value">
                                    <span className="stats-counter">{animatedValue}</span>
                                    <span className="stats-suffix">{stat.suffix}</span>
                                </div>
                                <p className="stats-label">{stat.label}</p>
                            </div>
                        );
                    })}
                </div>
            </div>
        </section>
    );
}

export default StatsSection;
